import anthropic, hashlib, json
from redis.asyncio import Redis

client = anthropic.Anthropic()

def _llm_cache_key(model: str, messages: list[dict], **kwargs) -> str:
    payload = {"model": model, "messages": messages, **kwargs}
    raw = json.dumps(payload, sort_keys=True)
    return "llm:" + hashlib.sha256(raw.encode()).hexdigest()

async def cached_message(
    redis: Redis,
    model: str,
    messages: list[dict],
    ttl: int = 3600,
    **kwargs,
) -> anthropic.types.Message:
    key = _llm_cache_key(model, messages, **kwargs)
    cached = await redis.get(key)
    if cached:
        # Reconstruct the Message object from the cached dict
        return anthropic.types.Message.model_validate_json(cached)

    response = client.messages.create(
        model=model, messages=messages, **kwargs
    )
    await redis.set(key, response.model_dump_json(), ex=ttl)
    return response

# Example: classification with caching
async def classify_intent(redis: Redis, user_message: str) -> str:
    response = await cached_message(
        redis,
        model="claude-haiku-4-5-20251001",
        messages=[
            {"role": "user", "content": f"Classify intent as one of [search, calculate, create, delete]: {user_message}"}
        ],
        max_tokens=10,
        ttl=86400,  # 24h — classification prompts rarely change
    )
    return response.content[0].text.strip()

from dataclasses import dataclass, field
import time

@dataclass
class CacheMetrics:
    hits: int = 0
    misses: int = 0
    errors: int = 0
    total_latency_ms: float = 0.0

    @property
    def hit_rate(self) -> float:
        total = self.hits + self.misses
        return self.hits / total if total else 0.0

_metrics: dict[str, CacheMetrics] = {}

def record_cache_event(cache_name: str, hit: bool, latency_ms: float) -> None:
    m = _metrics.setdefault(cache_name, CacheMetrics())
    if hit:
        m.hits += 1
    else:
        m.misses += 1
    m.total_latency_ms += latency_ms

def get_cache_stats() -> dict:
    return {
        name: {
            "hit_rate": m.hit_rate,
            "hits": m.hits,
            "misses": m.misses,
            "avg_latency_ms": m.total_latency_ms / max(m.hits + m.misses, 1),
        }
        for name, m in _metrics.items()
    }

# Example: instrument tool cache
async def dispatch_tool_instrumented(
    redis: Redis,
    tool_name: str,
    inputs: dict,
) -> dict:
    if tool_name not in CACHEABLE_TOOLS:
        return await execute_tool(tool_name, inputs)

    t0 = time.monotonic()
    cached = await tool_cache_get(redis, tool_name, inputs)
    latency = (time.monotonic() - t0) * 1000
    record_cache_event(f"tool:{tool_name}", hit=cached is not None, latency_ms=latency)

    if cached is not None:
        return cached

    result = await execute_tool(tool_name, inputs)
    await tool_cache_set(redis, tool_name, inputs, result)
    return result
